ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT ?title WHERE {
  ?comics a :Comics .
  ?publisher a :Publisher .
  ?comics p:hasPublisher ?publisher .
  ?comics p:Title ?title .
  ?comics p:SequentialArt ?sequentialart_w .
  ?comics p:SequentialArt ?sequentialart_w2 .
  ?publisher p:name ?name_w .
  FILTER((((STR(?sequentialart_w) = "Comic Book" || STR(?sequentialart_w2) = "Graphic Novel")) && STR(?name_w) = "BOOM Studios"))
} }
  low: { SELECT ?title WHERE {
  ?comics a :Comics .
  ?publisher a :Publisher .
  ?comics p:hasPublisher ?publisher .
  ?comics p:Title ?title .
  ?comics p:SequentialArt ?sequentialart_w .
  ?comics p:SequentialArt ?sequentialart_w2 .
  ?publisher p:name ?name_w .
  FILTER((STR(?sequentialart_w) = "Comic Book" || (STR(?sequentialart_w2) = "Graphic Novel" && STR(?name_w) = "BOOM Studios")))
} }
}
